INSERT INTO announcements (title, content, type, author, published_at, is_pinned, created_at) VALUES ('Inscription au Cycle de Doctorat 2025-2026', 'La Faculte des Sciences Ben M''Sick - Universite Hassan II de Casablanca informe l''ensemble des doctorants et des nouveaux candidats au doctorat du lancement du calendrier universitaire officiel pour l''annee academique 2025-2026.', 'INFO', 'Administration FSBM - Recherche', '2025-07-23 09:00:00', FALSE, NOW());
INSERT INTO announcements (title, content, type, author, published_at, is_pinned, created_at) VALUES ('Candidats convoques aux epreuves ecrites - Technologies de l''information', 'Liste des candidats convoques pour passer les epreuves ecrites en technologies de l''information, prevues le 06 juillet 2025.', 'INFO', 'Administration FSBM - Recherche', '2025-07-02 09:00:00', FALSE, NOW());
INSERT INTO announcements (title, content, type, author, published_at, is_pinned, created_at) VALUES ('Avis d''ouverture de candidature au poste de Chef de service', 'Avis d''ouverture de candidature au poste de Chef de service vacant a la Faculte des Sciences Ben M''Sick.', 'INFO', 'Administration FSBM - Services', '2025-07-02 09:00:00', FALSE, NOW());
INSERT INTO announcements (title, content, type, author, published_at, is_pinned, created_at) VALUES ('Resultat du Conseil de Discipline', 'Le Conseil de Discipline, reuni le 15 juin 2025, a statue sur plusieurs cas d''infractions au reglement interieur.', 'INFO', 'Administration FSBM - Campus', '2025-06-18 09:00:00', FALSE, NOW());
INSERT INTO announcements (title, content, type, author, published_at, is_pinned, created_at) VALUES ('Examens de la session 1 du printemps - S6 Licence d''Excellence', 'Publication de la liste des examens de la session 1 du printemps pour le semestre 6 de la Licence d''Excellence.', 'INFO', 'Administration FSBM - Recherche', '2025-06-04 09:00:00', FALSE, NOW());
INSERT INTO announcements (title, content, type, author, published_at, is_pinned, created_at) VALUES ('La FSBM renforce sa cybersecurite avec un nouveau partenaire strategique', 'A l''occasion du salon des nouvelles technologies, la FSBM a conclu un partenariat important avec un acteur majeur du domaine de la cybersecurite.', 'INFO', 'Administration FSBM - Partenariat', '2025-05-23 09:00:00', FALSE, NOW());
INSERT INTO announcements (title, content, type, author, published_at, is_pinned, created_at) VALUES ('Calendrier universitaire officiel 2025-2026', 'Publication du calendrier universitaire officiel de la Faculte des Sciences Ben M''Sick pour l''annee academique 2025-2026.', 'INFO', 'Administration FSBM - Campus', '2025-07-23 09:00:00', FALSE, NOW());
INSERT INTO announcements (title, content, type, author, published_at, is_pinned, created_at) VALUES ('Listes des etudiants inscrits 2025-2026', 'Les listes des etudiants inscrits par groupe et par section pour les semestres 2, 4 et 6 sont publiees pour les filieres IA, MI, PC et BG au titre de l''annee universitaire 2025-2026.', 'INFO', 'Administration FSBM - Campus', '2025-02-14 09:00:00', FALSE, NOW());
INSERT INTO announcements (title, content, type, author, published_at, is_pinned, created_at) VALUES ('Listes des inscrits - Session d''automne 2025-2026', 'Mise a jour des listes des inscrits pour la session d''automne de l''annee universitaire 2025-2026 (mise a jour du 10-11-2025).', 'INFO', 'Administration FSBM - Campus', '2025-10-10 09:00:00', FALSE, NOW());
INSERT INTO announcements (title, content, type, author, published_at, is_pinned, created_at) VALUES ('Mot du Doyen', 'La Faculte des Sciences Ben M''Sick (FSBM) est un etablissement ouvert et inclusif, fier de former chaque annee des milliers d''etudiants marocains et internationaux. Portee par une vision d''excellence, d''innovation et de responsabilite sociale, la FSBM s''engage a offrir un enseignement de qualite, a stimuler une recherche scientifique ambitieuse et a promouvoir une gouvernance moderne et participative. Au coeur de notre projet, nos etudiants, nos chercheurs et l''ensemble de notre personnel administratif sont pleinement impliques pour faire de la Faculte un pole de savoir rayonnant, au service du developpement durable de notre societe. Ensemble, construisons une FSBM plus forte, plus innovante et plus ouverte sur l''avenir.', 'INFO', 'Pr. Abdeslam EL BOUARI, Doyen de la FSBM', NOW(), TRUE, NOW());
INSERT INTO events (title, description, event_type, start_date, location, organizer, created_at) VALUES ('Journee Portes Ouvertes FSBM', 'Evenement representatif des activites de la FSBM (donnee dexemple).', 'PORTES_OUVERTES', '2026-09-25 09:00:00', 'Faculte des Sciences Ben M''Sick', 'FSBM', NOW());
INSERT INTO events (title, description, event_type, start_date, location, organizer, created_at) VALUES ('Forum de l''Emploi et des Stages', 'Evenement representatif des activites de la FSBM (donnee dexemple).', 'FORUM', '2026-10-08 09:00:00', 'Campus FSBM', 'FSBM', NOW());
INSERT INTO events (title, description, event_type, start_date, location, organizer, created_at) VALUES ('Conference : IA et Cybersecurite', 'Evenement representatif des activites de la FSBM (donnee dexemple).', 'CONFERENCE', '2026-07-15 14:00:00', 'Amphi FSBM', 'FSBM', NOW());
